fun rotate(arr: IntArray, k: Int): IntArray {
  val n = arr.size
  val shift = k % n
  return arr.takeLast(shift).toIntArray() + arr.dropLast(shift)
}

fun findDuplicates(arr: IntArray): Set<Int> {
  val seen = mutableSetOf<Int>()
  val dup = mutableSetOf<Int>()
  for (n in arr) {
    if (!seen.add(n)) dup.add(n)
  }
  return dup
}

fun hasPair(arr: IntArray, target: Int): Boolean {
  val set = mutableSetOf<Int>()
  for (num in arr) {
    if (target - num in set) return true
    set.add(num)
  }
  return false
}

