fun longestUnique(s: String): Int {
  val set = mutableSetOf<Char>()
  var l = 0
  var max = 0
  for (r in s.indices) {
    while (s[r] in set) {
      set.remove(s[l])
      l++
    }
    set.add(s[r])
    max = maxOf(max, r - l + 1)
  }
  return max
}

