fun secondLargest(arr: IntArray): Int {
  var first = Int.MIN_VALUE
  var second = Int.MIN_VALUE
  for (n in arr) {
    if (n > first) {
      second = first
      first = n
    } else if (n > second && n != first) {
      second = n
    }
  }
  return second
}

