fun maxSubArray(arr: IntArray): Int {
  var maxSum = arr[0]
  var curr = arr[0]
  for (i in 1 until arr.size) {
    curr = maxOf(arr[i], curr + arr[i])
    maxSum = maxOf(maxSum, curr)
  }
  return maxSum
}

fun majority(arr: IntArray): Int {
  var count = 0
  var candidate = 0
  for (num in arr) {
    if (count == 0) candidate = num
    count += if (num == candidate) 1 else -1
  }
  return candidate
}

fun trap(height: IntArray): Int {
  var left = 0
  var right = height.size - 1
  var leftMax = 0
  var rightMax = 0
  var water = 0

  while (left < right) {
    if (height[left] < height[right]) {
      if (height[left] >= leftMax) leftMax = height[left]
      else water += leftMax - height[left]
      left++
    } else {
      if (height[right] >= rightMax) rightMax = height[right]
      else water += rightMax - height[right]
      right--
    }
  }
  return water
}

fun merge(intervals: Array<IntArray>): List<IntArray> {
  intervals.sortBy { it[0] }
  val result = mutableListOf<IntArray>()
  var current = intervals[0]

  for (i in 1 until intervals.size) {
    if (intervals[i][0] <= current[1]) {
      current[1] = maxOf(current[1], intervals[i][1])
    } else {
      result.add(current)
      current = intervals[i]
    }
  }
  result.add(current)
  return result
}

fun minWindow(s: String, t: String): String {
  val map = mutableMapOf<Char, Int>()
  for (c in t) map[c] = map.getOrDefault(c, 0) + 1

  var left = 0
  var count = t.length
  var minLen = Int.MAX_VALUE
  var start = 0

  for (right in s.indices) {
    if (map.getOrDefault(s[right], 0) > 0) count--
    map[s[right]] = map.getOrDefault(s[right], 0) - 1

    while (count == 0) {
      if (right - left + 1 < minLen) {
        minLen = right - left + 1
        start = left
      }
      map[s[left]] = map.getOrDefault(s[left], 0) + 1
      if (map[s[left]]!! > 0) count++
      left++
    }
  }
  return if (minLen == Int.MAX_VALUE) "" else s.substring(start, start + minLen)
}

fun groupAnagrams(strs: Array<String>): List<List<String>> {
  val map = mutableMapOf<String, MutableList<String>>()
  for (str in strs) {
    val key = str.toCharArray().sorted().joinToString("")
    map.getOrPut(key) { mutableListOf() }.add(str)
  }
  return map.values.toList()
}

fun longestPalindrome(s: String): String {
  var res = ""
  for (i in s.indices) {
    for (j in i until s.length) {
      val sub = s.substring(i, j + 1)
      if (sub == sub.reversed() && sub.length > res.length) {
        res = sub
      }
    }
  }
  return res
}

fun productExceptSelf(nums: IntArray): IntArray {
  val result = IntArray(nums.size)
  var prefix = 1

  for (i in nums.indices) {
    result[i] = prefix
    prefix *= nums[i]
  }

  var suffix = 1
  for (i in nums.size - 1 downTo 0) {
    result[i] *= suffix
    suffix *= nums[i]
  }

  return result
}

